+.skills-header {
+  display: flex;
+  align-items: flex-end;
+  justify-content: space-between;
+  gap: 18px;
+  flex-wrap: wrap;
+  margin-bottom: 22px;
+}
+
+.skills-toolbar {
+  display: grid;
+  gap: 10px;
+  padding: 14px 16px;
+  border-radius: 18px;
+  border: 1px solid rgba(255, 107, 74, 0.18);
+  background: linear-gradient(135deg, var(--surface), var(--surface-muted));
+  min-width: min(520px, 100%);
+}
+
+.skills-search {
+  display: flex;
+  align-items: center;
+  border-radius: 999px;
+  border: 1px solid rgba(255, 107, 74, 0.2);
+  background: rgba(255, 255, 255, 0.45);
+  padding: 10px 14px;
+}
+
+[data-theme="dark"] .skills-search {
+  background: rgba(24, 19, 16, 0.55);
+  border-color: rgba(255, 131, 95, 0.35);
+}
+
+.skills-search-input {
+  border: none;
+  outline: none;
+  width: 100%;
+  font-size: 0.95rem;
+  background: transparent;
+}
+
+.skills-toolbar-row {
+  display: flex;
+  align-items: center;
+  justify-content: flex-end;
+  gap: 10px;
+  flex-wrap: wrap;
+}
+
+.skills-sort {
+  appearance: none;
+  border: 1px solid rgba(255, 107, 74, 0.2);
+  border-radius: 999px;
+  padding: 10px 14px;
+  background: rgba(255, 255, 255, 0.45);
+  color: var(--ink);
+  font-weight: 650;
+  font-size: 0.9rem;
+  cursor: pointer;
+}
+
+[data-theme="dark"] .skills-sort {
+  background: rgba(24, 19, 16, 0.55);
+  border-color: rgba(255, 131, 95, 0.35);
+}
+
+.skills-dir,
+.skills-view {
+  border: 1px solid rgba(255, 107, 74, 0.2);
+  border-radius: 999px;
+  padding: 10px 12px;
+  background: rgba(255, 255, 255, 0.45);
+  color: var(--ink);
+  font-weight: 700;
+  cursor: pointer;
+}
+
+[data-theme="dark"] .skills-dir,
+[data-theme="dark"] .skills-view {
+  background: rgba(24, 19, 16, 0.55);
+  border-color: rgba(255, 131, 95, 0.35);
+}
+
+.skills-view.is-active {
+  background: rgba(255, 107, 74, 0.16);
+  border-color: rgba(255, 107, 74, 0.32);
+  color: var(--accent-deep);
+}
+
+.skills-list {
+  display: grid;
+  gap: 0;
+  border-radius: var(--radius-md);
+  border: 1px solid var(--line);
+  overflow: hidden;
+  background: var(--surface);
+}
+
+.skills-row {
+  display: grid;
+  grid-template-columns: minmax(0, 1fr) auto;
+  gap: 18px;
+  padding: 16px 18px;
+  text-decoration: none;
+  color: inherit;
+  border-bottom: 1px solid var(--line);
+  transition: background 0.15s ease;
+}
+
+.skills-row:last-child {
+  border-bottom: none;
+}
+
+.skills-row:hover {
+  background: rgba(255, 107, 74, 0.07);
+}
+
+[data-theme="dark"] .skills-row:hover {
+  background: rgba(232, 106, 71, 0.11);
+}
+
+.skills-row-main {
+  display: grid;
+  gap: 6px;
+  min-width: 0;
+}
+
+.skills-row-title {
+  display: flex;
+  align-items: baseline;
+  gap: 10px;
+  flex-wrap: wrap;
+  font-family: var(--font-display);
+  font-size: 1.1rem;
+  letter-spacing: -0.02em;
+}
+
+.skills-row-slug {
+  font-family: var(--font-mono);
+  font-size: 0.85rem;
+  color: var(--ink-soft);
+}
+
+.skills-row-summary {
+  color: var(--ink-soft);
+  font-size: 0.95rem;
+  line-height: 1.45;
+  overflow: hidden;
+  text-overflow: ellipsis;
+  display: -webkit-box;
+  -webkit-line-clamp: 2;
+  -webkit-box-orient: vertical;
+}
+
+.skills-row-metrics {
+  display: flex;
+  align-items: center;
+  justify-content: flex-end;
+  gap: 14px;
+  font-family: var(--font-mono);
+  font-size: 0.85rem;
+  color: var(--ink-soft);
+  white-space: nowrap;
+}
+
+.skills-row-metrics span {
+  display: inline-flex;
+  gap: 6px;
+  align-items: center;
+}
+
 .card {
   background: var(--surface);
   border-radius: var(--radius-md);
